function App (){
  const [ arrayData, setArrayData ] = React.useState([
    {
      id: '',
      name: 'Ray',
      price: 80,
    },
    {
      name: 'John',
      price: 90,
    },
    {
      name: 'Mary',
      price: 100,
    }
  ]);

  function sayHi () {
    setArrayData([ ...arrayData.reverse() ])
  }

  return (
    <div>
      <ul>
        { arrayData.map((item) => (
          <li>{ item.name } - <input type="text"/></li>
        )) }
      </ul>
      <button type="button" onClick={ sayHi }>反轉</button>
    </div>
  )
}

const app = document.querySelector('#app');
